import{_ as t,o as d,c as o,a2 as a}from"./chunks/framework.ByXR59UU.js";const u=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/user-guide/configuration.md","filePath":"openshield-xdp/user-guide/configuration.md","lastUpdated":null}'),c={name:"openshield-xdp/user-guide/configuration.md"};function r(i,e,n,s,l,h){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>Runtime config at <code>/etc/openshield/openshield.yaml</code>.</p><h2 id="interface-xdp-mode" tabindex="-1">interface / xdp_mode <a class="header-anchor" href="#interface-xdp-mode" aria-label="Permalink to &quot;interface / xdp_mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Default</th><th>Values</th></tr></thead><tbody><tr><td><code>interface</code></td><td><code>eno1</code></td><td>Any NIC name</td></tr><tr><td><code>xdp_mode</code></td><td><code>auto</code></td><td><code>auto</code>, <code>native</code>, <code>generic</code>, <code>offload</code></td></tr></tbody></table><p><code>auto</code> tries offload → native → generic in order.</p><h2 id="static-—-rate-thresholds" tabindex="-1">static — Rate thresholds <a class="header-anchor" href="#static-—-rate-thresholds" aria-label="Permalink to &quot;static — Rate thresholds&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>enabled</code></td><td><code>true</code></td><td>Master switch for per-IP rate limiting</td></tr><tr><td><code>pps_threshold</code></td><td><code>1000</code></td><td>Max packets/s per IP before scoring</td></tr><tr><td><code>syn_pps_threshold</code></td><td><code>200</code></td><td>Max SYN/s per IP</td></tr><tr><td><code>suspicion_threshold</code></td><td><code>100</code></td><td>Cumulative score to trigger ban</td></tr><tr><td><code>ban_duration</code></td><td><code>3600</code></td><td>Ban duration in seconds</td></tr><tr><td><code>suspicion_decay</code></td><td><code>0.5</code></td><td>Score retention per window (50%)</td></tr><tr><td><code>rate_limit_mode</code></td><td><code>threshold</code></td><td><code>threshold</code> or <code>token_bucket</code></td></tr></tbody></table><h2 id="dynamic-—-advanced-detection" tabindex="-1">dynamic — Advanced detection <a class="header-anchor" href="#dynamic-—-advanced-detection" aria-label="Permalink to &quot;dynamic — Advanced detection&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>synproxy_enabled</code></td><td><code>false</code></td><td>Cookie-based SYN flood mitigation</td></tr><tr><td><code>entropy_spoof_enabled</code></td><td><code>true</code></td><td>Detect spoofed-source floods</td></tr><tr><td><code>ttl_anomaly_enabled</code></td><td><code>true</code></td><td>Per-IP TTL deviation</td></tr><tr><td><code>conn_rate_limit</code></td><td><code>5000</code></td><td>Max SYN/s per IP</td></tr><tr><td><code>auto_escalation_threshold</code></td><td><code>5</code></td><td>Bans per /24 before subnet ban</td></tr><tr><td><code>mac_filter_enabled</code></td><td><code>false</code></td><td>MAC whitelist/blacklist</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Full reference</p><p>See <a href="/pingless-studios-docs/openshield-xdp/reference/configuration">Configuration Reference</a> for every field.</p></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/reference/cli">CLI Reference</a> · <a href="/pingless-studios-docs/openshield-xdp/detection-engine/overview">Detection</a></p>',12)])])}const f=t(c,[["render",r]]);export{u as __pageData,f as default};
